var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_QM","text":{"KOREA":"흠흠, 좋아. 부엌에서 풍기던 향기 그대로야.","JPN":"ふんふん、よし。キッチンで漂ってた匂いとそっくり。","ENG":"Ahem. Good. The kitchen smells how it always has.","TWN":"嗯嗯，好了。跟廚房裡的香味一模一樣。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_QM","text":{"KOREA":"배는 안 고프시려나? 치킨 수프도 있으면 좋았을 텐데…….","JPN":"お腹は空いていらっしゃらないかな？　チキンスープもあればよかったんだけど……","ENG":"I wonder if she's hungry. It would've been better if we had some chicken soup too...","TWN":"你不餓嗎？要是有雞湯就好了……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"으음, 음…….","JPN":"うーん、うん……","ENG":"Mm... Ngh...","TWN":"呃嗯，嗯……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이 목소리는……. 분명…….","JPN":"この声は……確か……","ENG":"That voice... It has to be–","TWN":"這聲音……分明是……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"콜록!! 콜록!! 하아……! 하……!","JPN":"ゴホッ！！　ゴホッ！！　はあ……！　は……！","ENG":"*Cough!!* *Cough!!* *Huff...* *Huff...!*","TWN":"咳咳！！咳咳！！哈啊……！哈……！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_QM","text":{"KOREA":"앗! 안 돼요, 부학회장님! 지금 일어나려고 하시면……!","JPN":"あっ！　だめですよ、副学会長様！　今起き上がろうとされては……！","ENG":"Huh?! No, Vice President! Don't try to get up...!","TWN":"啊！不可以，副學會長！你現在起來的話……！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_QM","text":{"KOREA":"부학회장님, 괜찮으세요?","JPN":"副学会長様、大丈夫ですか？","ENG":"Are you okay?","TWN":"副學會長，你沒事吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_QM","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP"},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"콜록, 어떻게…… 어떻게 된 거예요? 제가 왜…….","JPN":"ゲホッ……どうして……どうなっているのですか？　私はなぜ……","ENG":"*Cough* What... What happened? Why am I...?","TWN":"咳咳，怎麼……怎麼回事？我為什麼……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_QM","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_QM","text":{"KOREA":"몸을 뒤척이시다 침대에서 굴러 떨어지셨어요.","JPN":"寝返りをうたれた際にベッドから転げ落ちられたのです。","ENG":"You fell off your bed while you were sleeping.","TWN":"你翻身的時候從床上滾下來了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_QM","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_QM","text":{"KOREA":"그래도 정신이 드셔서 다행이에요. 한동안 죽은 듯이 주무시기만 해서 걱정했어요.","JPN":"ですが、お目覚めになられて安心しました。しばらく死んだように眠っていらしたので心配していたんです。","ENG":"But I'm glad you finally woke up. You've been sleeping for so long that I was getting worried.","TWN":"不過幸好你清醒過來了。你像死掉一樣睡了好久，我很擔心你。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_QM","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제가 왜 이런 데 있죠? 분명 서재에서 잠시 눈을 붙였는데….","JPN":"私はなぜこんなところにいるのでしょうか？　書斎で仮眠をとっていたはずですのに……","ENG":"Why am I here? I am certain I fell asleep in my office...","TWN":"我為什麼會在這裡？我明明就是在書房裡打瞌睡……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_QM","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"머리가 무거워…. 몸은 또 왜 이렇게 욱신거리는 거죠…?","JPN":"頭が重い……体もひどく痛むようですし……","ENG":"My head is throbbing... And why does my body feel so heavy...?","TWN":"頭好重……身體又為什麼這麼酸痛……？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_QM","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_QM","text":{"KOREA":"편찮으셔서 그래요. 요양을 하러 오셨다고 전해 들었거든요.","JPN":"お体の具合が良くないからだと思います。療養に来られたと聞きました。","ENG":"You're ill. I was told you came here to recuperate.","TWN":"因為你生病了，我聽說你是來休養的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_QM","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_QM","text":{"KOREA":"여기 있는 뱅쇼 좀 드셔 보세요. 기운이 좀 나실 거예요.","JPN":"ホットワインはいかがですか？　元気がでますよ。","ENG":"Here, have some vin chaud. It'll make you feel better.","TWN":"請你嘗嘗這裡的熱紅酒。喝了之後就會有精神了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_QM","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"후우…. 고마워요. 이제 좀 살겠어요.","JPN":"ふう……ありがとう。生き返った気がしますわ。","ENG":"Huu... Thank you. I do feel a lot better now.","TWN":"呼……謝謝你，我感覺好多了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_QM","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_QM","text":{"KOREA":"역시 잘 들을 줄 알았어요. 감기에 걸렸을 때는 뱅쇼가 즉효약이거든요.","JPN":"思っていたとおり効き目がありましたね。風邪にはホットワインがよく効くんです。","ENG":"I knew it would do wonders. Vin chaud always does the trick for my colds.","TWN":"我就知道會有效。感冒的時候，熱紅酒就是特效藥。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_QM","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"감기 말인가요?","JPN":"風邪ですか？","ENG":"Colds?","TWN":"感冒嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_QM","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_QM","text":{"KOREA":"네. 저도 어릴 때 몸이 약해서 자주 마셨어요.","JPN":"はい。私も小さい頃に体が弱くてよく飲んでいました。","ENG":"Yes. I used to catch colds all the time when I was young.","TWN":"是啊。我小時候也因為身體不好經常喝的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_QM","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"감기라면 보통 고약한 독감이 아니겠네요. 카운터인 제가 정신을 못 차릴 정도니까요.","JPN":"風邪でしたら相当症状の重いインフルエンザでしょうね。カウンターである私が寝込んでしまうほどですから。","ENG":"This feels more like the flu than a cold. It is strong enough to knock out a Counter like me.","TWN":"如果說是感冒，應該很厲害的流感吧。畢竟連身為制裁者的我都提不起精神了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_QM","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그런데 저를 부학회장이라고 부르시더군요.","JPN":"ところで、私のことを副学会長と呼んでいましたが。","ENG":"By the way, you have been calling me \\"Vice President\\".","TWN":"不過你剛才叫我副學會長。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_QM","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"행색이 기관 소속은 아닌 것 같은데…. 학회 사람인가요?","JPN":"格好からして機関の所属には見えませんが……学会の方ですの？","ENG":"However, I do not think you are from the Institution... Are you a member of the Society?","TWN":"看你的穿著打扮，不像是機關的人……你是學會的人嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_QM","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_QM","text":{"KOREA":"아…….","JPN":"あ……","ENG":"Oh...","TWN":"啊……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_QM","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_QM","text":{"KOREA":"네. 부학회장님을 모시게 되어 영광이에요. 실키라고 불러 주세요.","JPN":"はい。副学会長様にお仕えできて光栄です。シルキーとお呼びください。","ENG":"Yes. It's an honor to meet you, Vice President. Please call me Sylkie.","TWN":"是的，很榮幸能照顧副學會長。你可以叫我思琪。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"좋아요, 실키. 인사는 생략하고 먼저 한 가지 확실하게 해 두죠.","JPN":"わかりました、シルキー。挨拶はこれくらいにして、まず一つだけはっきりさせましょう。","ENG":"Very well, Sylkie. But let me make myself clear.","TWN":"好的，思琪。寒暄就免了，我們先弄清楚一件事。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저는 요양 따위 온 적 없습니다. 애초에 여기가 어딘지도 몰라요.","JPN":"私は療養に来た覚えはありません。そもそもここがどこであるかも知りませんわ。","ENG":"I am not here to recuperate. Even more so, I do not know where I am.","TWN":"我根本就沒來休養，也不知道這裡是哪裡。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"더 누워 계세요, 부학회장님. 지금은 쉬셔야 해요.","JPN":"もう少し横におなりください、副学会長様。今はお休みにならないと。","ENG":"Please, lie down, ma'am. You need your rest.","TWN":"你再躺一會兒吧，副學會長。你現在需要休息。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아뇨. 제가 왜 여기 와 있는지 확인해야겠어요.","JPN":"いいえ。なぜここに来ているのか確認するのが先ですわ。","ENG":"No. I must find out why I am I here.","TWN":"不，我得弄清楚我為什麼會來這裡。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"설마 이 건물에 당신과 저만 있지는 않겠죠.","JPN":"まさかこの建物にあなたと私だけということはないでしょうから。","ENG":"You and I are not the only people here, are we?","TWN":"這棟樓裡不會就你跟我兩個人吧。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"잠깐만요, 부학회장님. 적어도 먼저 기운을 차리신 다음에……","JPN":"お待ちください、副学会長様。少なくともお元気になられてから……","ENG":"Please, Vice President. I'll answer your questions once you're better...","TWN":"你等一下，副學會長。至少等到你恢復精神再……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_A","text":{"KOREA":"음?","JPN":"うむ？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_NPC_ESPR2_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_B","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_A","text":{"KOREA":"부학회장님? 부학회장님 맞으십니까?","JPN":"副学会長？　副学会長ですか？","ENG":"Vice President? Is that really you?","TWN":"副學會長？你是副學會長沒錯吧？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_NPC_ESPR2_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_B","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_B","text":{"KOREA":"동요하지 마. 어서 루나 님을 호출해.","JPN":"動揺するな。早くルナ様を呼べ。","ENG":"Snap out of it! Go get Ms. Luna!","TWN":"別慌，快呼叫露娜。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_NPC_ESPR2_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_B","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"반응이 별나시네요. 꼭 제가 여기 있으면 안 되는 것처럼.","JPN":"妙な反応ですわね。まるで私がここにいてはいけないかのような。","ENG":"What an odd reaction. You act as if I am not supposed to be here.","TWN":"反應好奇怪，就好像我不能在這裡一樣。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_B","text":{"KOREA":"학회를 위해 주어진 역할을 다하고 있을 뿐입니다.","JPN":"学会のために、与えられた役割に最善を尽くしているだけです。","ENG":"I am merely doing my duties for the Society.","TWN":"我們只是在為了學會履行自己的職責。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_B","text":{"KOREA":"어째서 나오셨습니까? 외출은 몸에 해롭습니다.","JPN":"部屋をお出にならなければいけない理由でもございましたか？　外出はお体にさわります。","ENG":"Why did you come out? You should be in your bed.","TWN":"你怎麼出來了？外出對你的身體不好。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"질문은 제가 합니다. 묻는 말에나 대답하세요.","JPN":"質問は私がいたしますわ。まず問いに答えなさい。","ENG":"I will ask the questions here. Now, tell me.","TWN":"我來提問。我問什麼，你們就答什麼。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"여기는 어디죠? 서재에서 잠들었던 제가 왜 여기서 깨어난 거고요?","JPN":"ここはどこですか？　書斎で眠っていたはずなのに、なぜここで目覚めたのですか？","ENG":"Where am I? How did I end up here when I fell asleep in my office?","TWN":"這裡是哪裡？我原本只是在書房裡睡著，為什麼會在這裡醒來？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_B","text":{"KOREA":"죄송하지만 저희는 아무것도 대답해 드릴 수 없습니다.","JPN":"申し訳ございませんが、私たちは何もお答えできません。","ENG":"My apologies, but I cannot answer that.","TWN":"對不起，我們不能回答你的任何問題。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"왜 대답 못 하는 거죠? 인신공양을 금지하니까 그 대신 저를 산제물로 바치려고요?","JPN":"どうして答えられないのですか？　人身御供を禁止したから、代わりに私を生贄として捧げるつもりですか？","ENG":"Why can you not? Are you planning on using me as sacrifice because I banned it?","TWN":"為什麼不能回答？因為我禁止活人祭祀，所以就想把我當成祭物獻祭嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"방금 무슨 소리죠? 복도 끝에 있는 방에서 들린 건가요?","JPN":"今の音は何ですか？　廊下の先にある部屋からでしょうか。","ENG":"What was that? Did that come from a room at the far end of the corridor?","TWN":"剛才是什麼聲音？是從走廊盡頭的房間裡傳出來的嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_B","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"좋아요. 이것마저 대답할 생각이 없군요.","JPN":"いいでしょう。答えるつもりはないようですね。","ENG":"Very well. I see you have no intent on answering.","TWN":"很好。連這個也不想回答我是吧。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당장 제 앞에서 비키세요. 이 시설이 뭐 하는 곳인지 직접 확인해 봐야겠습니다.","JPN":"今すぐそこをどきなさい。この施設が何をするところなのか、直接確かめます。","ENG":"Then get out of my way. I will find out for myself what this place really is.","TWN":"馬上給我讓開。我要親自弄清楚這裡到底是哪。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_B","text":{"KOREA":"저희 역할은 부학회장님께서 요양 기간을 조용히 보내실 수 있게 돕는 것입니다.","JPN":"私たちの役割は副学会長が療養の期間中、静かにお過ごしいただけるようサポートすることです。","ENG":"Our orders are to assist you in spending your recuperation period here quietly, Vice President.","TWN":"我們的職責是保證副學會長可以安靜地休養。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"조용히? 그 말을 방해꾼 취급이라고 해석해도 될까요?","JPN":"静かに？　その言葉、邪魔者扱いと理解しますが？","ENG":"\\"Quietly\\"? Does that mean I am some kind of intruder here?","TWN":"安靜？也就是說，我可以理解為自己被當成絆腳石嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_B","text":{"KOREA":"…침실에 들어가 계십시오.","JPN":"……寝室にお戻りください。","ENG":"Please, go back into your room.","TWN":"……請你回臥室。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_B","text":{"KOREA":"거절하시면 저희로서는 다른 도리가 없습니다.","JPN":"拒否なさるなら、私たちもやむをえません。","ENG":"If you refuse, then we will have to use rather aggressive measures.","TWN":"如果你拒絕，我們就沒有別的辦法了。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저는 부학회장이기 이전에 맥크레디 가문의 유일하고도 정당한 후계자입니다.","JPN":"私は副学会長である前にマクレディー家の唯一かつ正当な後継者です。","ENG":"I am the rightful heir of the MacCready family before I am your Vice President.","TWN":"我是副學會長，更是麥克蕾蒂家族唯一的合法繼承人。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"학회의 어느 누구도 저에게 지시할 수는 없어요.","JPN":"学会の誰も私に指図することはできませんわ。","ENG":"There is no one here who can order me around.","TWN":"所以學會的任何人，都不能命令我。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"설령 그게 학회장일지라도!","JPN":"たとえそれが学会長であってもです！","ENG":"Even if that is the President!","TWN":"哪怕那個人是學會長！"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};